                      <span style={{ fontSize:"10px", fontFamily:"'EB Garamond',serif", padding:"2px 8px", borderRadius:"2px", background:v==="perfect"?`${C.gold}18`:C.creamDk, color:bsColor[v] }}>{bsLabel[v]}</span>
