// PAIRING WHEELS COMPONENT
// ═══════════════════════════════════════════════════════════════════
// ─── GEOMETRY HELPERS ────────────────────────────────────────────────────────
const PW_CX = 300, PW_CY = 300, PW_R = 270;
function pw_toRad(deg) { return (deg - 90) * Math.PI / 180; }
function pw_polar(deg, r) {
  const a = pw_toRad(deg);
  return [PW_CX + r * Math.cos(a), PW_CY + r * Math.sin(a)];
}
function pw_arcPath(s, e, ir, outerR) {
  if (e < s) e += 360;
  const sa = pw_toRad(s), ea = pw_toRad(e);
  const lg = (e - s) > 180 ? 1 : 0;
  const [x1,y1] = [PW_CX+outerR*Math.cos(sa), PW_CY+outerR*Math.sin(sa)];
  const [x2,y2] = [PW_CX+outerR*Math.cos(ea), PW_CY+outerR*Math.sin(ea)];
  const [x3,y3] = [PW_CX+ir*Math.cos(ea), PW_CY+ir*Math.sin(ea)];
  const [x4,y4] = [PW_CX+ir*Math.cos(sa), PW_CY+ir*Math.sin(sa)];
  return `M${x1},${y1} A${outerR},${outerR},0,${lg},1,${x2},${y2} L${x3},${y3} A${ir},${ir},0,${lg},0,${x4},${y4} Z`;
}
function pw_midAngle(s, e) {
  if (e < s) e += 360;
  return s + (e - s) / 2;
}

