// ─── SVG GEOMETRY ─────────────────────────────────────────────────────────────
const SW_CX = 300, SW_CY = 300, SW_R = 268;
function sw_rad(deg) { return (deg - 90) * Math.PI / 180; }
function sw_polar(deg, r) { const a = sw_rad(deg); return [SW_CX + r*Math.cos(a), SW_CY + r*Math.sin(a)]; }
function sw_arc(s, e, ri, ro) {
  if (e <= s) e += 360;
  const sa = sw_rad(s), ea = sw_rad(e), lg = (e-s)>180?1:0;
  const [x1,y1]=[SW_CX+ro*Math.cos(sa), SW_CY+ro*Math.sin(sa)];
  const [x2,y2]=[SW_CX+ro*Math.cos(ea), SW_CY+ro*Math.sin(ea)];
  const [x3,y3]=[SW_CX+ri*Math.cos(ea), SW_CY+ri*Math.sin(ea)];
  const [x4,y4]=[SW_CX+ri*Math.cos(sa), SW_CY+ri*Math.sin(sa)];
  return `M${x1},${y1} A${ro},${ro},0,${lg},1,${x2},${y2} L${x3},${y3} A${ri},${ri},0,${lg},0,${x4},${y4} Z`;
}

